from flask import Flask, request
from web3 import Web3, HTTPProvider

app = Flask(__name__)
w3 = Web3(HTTPProvider('http://localhost:8545'))  # connect to geth node

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    if not 'message' in data or not 'signature' in data:
        return {'error': 'Invalid request, missing parameters'}, 400
        
    message = data['message']
    signature = data['signature']
    
    # recover the address from the signed message
    try:
        recovered_address = w3.eth.account.recoverHash(Web3.sha3(text=message), signature=signature)
    except Exception as e:
        return {'error': str(e)}, 500
        
    # verify that the recovered address is correct (replace with actual user's wallet address)
    if recovered_address == 'user_wallet_address':
        return {'success': True}, 200
    else:
        return {'error': 'Invalid signature'}, 403

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=5000)